sql:
SELECT *
FROM options_data
WHERE strike_price = 0.0;

SELECT strike_price, close_price, underlying_asset, daily_hv, intra_hv
FROM options_data
ORDER BY strike_price DESC;

SELECT underlying_asset, expiration_date, strike_price, implied_volatility
FROM options_data
WHERE underlying_asset = 'CGNX';

SELECT AVG(implied_volatility)
FROM options_data
WHERE close_price > (SELECT AVG(close_price) FROM market_data);

SELECT predicted_price, confidence_level, model_used
FROM predictions
WHERE strike_price = 1.0;

external_knowledge:
- The 'strike price' is the predetermined price at which a call option can be exercised; 
- The 'closing price' refers to the last price at which the underlying asset was traded on a given trading day; 
- 'Total trade quantity' and 'total trade price' give insights into the trading activity's volume and value, respectively.

sql:
SELECT hv_id, strike_price, expiration_date, historical_volatility
FROM historical_volatility
WHERE strike_price = historical_volatility;

SELECT strike_price
FROM predictions
WHERE model_used = (SELECT model_name FROM prediction_models WHERE model_id = 1);

SELECT ta.trade_time, SUM(ta.quantity) AS cumulative_volume
FROM trading_activity ta
GROUP BY ta.trade_time;

SELECT strike_price, predicted_price, confidence_level
FROM predictions
WHERE predicted_price = (SELECT MAX(predicted_price) FROM predictions);

SELECT strike_price, expiration_date
FROM options_data
WHERE daily_hv > 0.2 AND implied_volatility < 50;
